20	#include "kernel/register.h"
21	#include "kernel/celltypes.h"
22	#include "kernel/rtlil.h"
23	#include "kernel/log.h"
24	
25	USING_YOSYS_NAMESPACE
26	PRIVATE_NAMESPACE_BEGIN
27	
28	struct SynthIce40Pass : public ScriptPass
29	{
30		SynthIce40Pass() : ScriptPass("synth_ice40", "synthesis for iCE40 FPGAs") { }
31	
32		void on_register() override
33		{
34			RTLIL::constpad["synth_ice40.abc9.hx.W"] = "250";
35			RTLIL::constpad["synth_ice40.abc9.lp.W"] = "400";
36			RTLIL::constpad["synth_ice40.abc9.u.W"] = "750";
37		}
38	
39		void help() override
40		{
41			//   |---v---|---v---|---v---|---v---|---v---|---v---|---v---|---v---|---v---|---v---|
42			log("\n");
43			log("    synth_ice40 [options]\n");
44			log("\n");
45			log("This command runs synthesis for iCE40 FPGAs.\n");
46			log("\n");
47			log("    -device < hx | lp | u >\n");
48			log("        relevant only for '-abc9' flow, optimise timing for the specified\n");
49			log("        device. default: hx\n");
50			log("\n");
51			log("    -top <module>\n");
52			log("        use the specified module as top module\n");
53			log("\n");
54			log("    -blif <file>\n");
55			log("        write the design to the specified BLIF file. writing of an output file\n");
56			log("        is omitted if this parameter is not specified.\n");
57			log("\n");
58			log("    -edif <file>\n");
59			log("        write the design to the specified EDIF file. writing of an output file\n");
60			log("        is omitted if this parameter is not specified.\n");
61			log("\n");
62			log("    -json <file>\n");
63			log("        write the design to the specified JSON file. writing of an output file\n");
64			log("        is omitted if this parameter is not specified.\n");
65			log("\n");
66			log("    -run <from_label>:<to_label>\n");
67			log("        only run the commands between the labels (see below). an empty\n");
68			log("        from label is synonymous to 'begin', and empty to label is\n");
69			log("        synonymous to the end of the command list.\n");
70			log("\n");
71			log("    -noflatten\n");
72			log("        do not flatten design before synthesis\n");
73			log("\n");
74			log("    -dff\n");
75			log("        run 'abc'/'abc9' with -dff option\n");
76			log("\n");
77			log("    -retime\n");
78			log("        run 'abc' with '-dff -D 1' options\n");
79			log("\n");
80			log("    -nocarry\n");
81			log("        do not use SB_CARRY cells in output netlist\n");
82			log("\n");
83			log("    -nodffe\n");
84			log("        do not use SB_DFFE* cells in output netlist\n");
85			log("\n");
86			log("    -dffe_min_ce_use <min_ce_use>\n");
87			log("        do not use SB_DFFE* cells if the resulting CE line would go to less\n");
88			log("        than min_ce_use SB_DFFE* in output netlist\n");
89			log("\n");
90			log("    -nobram\n");
91			log("        do not use SB_RAM40_4K* cells in output netlist\n");
92			log("\n");
93			log("    -spram\n");
94			log("        enable automatic inference of SB_SPRAM256KA\n");
95			log("\n");
96			log("    -dsp\n");
97			log("        use iCE40 UltraPlus DSP cells for large arithmetic\n");
98			log("\n");
99			log("    -noabc\n");
100			log("        use built-in Yosys LUT techmapping instead of abc\n");
101			log("\n");
102			log("    -abc2\n");
103			log("        run two passes of 'abc' for slightly improved logic density\n");
104			log("\n");
105			log("    -vpr\n");
106			log("        generate an output netlist (and BLIF file) suitable for VPR\n");
107			log("        (this feature is experimental and incomplete)\n");
108			log("\n");
109			log("    -noabc9\n");
110			log("        disable use of new ABC9 flow\n");
111			log("\n");
112			log("    -flowmap\n");
113			log("        use FlowMap LUT techmapping instead of abc (EXPERIMENTAL)\n");
114			log("\n");
115			log("    -no-rw-check\n");
116			log("        marks all recognized read ports as \"return don't-care value on\n");
117			log("        read/write collision\" (same result as setting the no_rw_check\n");
118			log("        attribute on all memories).\n");
119			log("\n");
120			log("    -latches <info|warn|error>\n");
121			log("        select the behaviour for latches that cannot be mapped to a\n");
122			log("        dedicated hardware primitive and are implemented using LUTs\n");
123			log("        instead. 'error' (the default) aborts synthesis, 'warn' only\n");
124			log("        prints a warning, and 'info' permits them with an info-level message.\n");
125			log("\n");
126			log("\n");
127			log("The following commands are executed by this synthesis command:\n");
128			help_script();
129			log("\n");
130		}
131	
132		string top_opt, blif_file, edif_file, json_file, device_opt, latches;
133		bool nocarry, nodffe, nobram, spram, dsp, flatten, retime, noabc, abc2, vpr, abc9, dff, flowmap, no_rw_check;
134		int min_ce_use;
135	
136		void clear_flags() override
137		{
138			top_opt = "-auto-top";
139			blif_file = "";
140			edif_file = "";
141			json_file = "";
142			nocarry = false;
143			nodffe = false;
144			min_ce_use = -1;
145			nobram = false;
146			spram = false;
147			dsp = false;
148			flatten = true;
149			retime = false;
150			noabc = false;
151			abc2 = false;
152			vpr = false;
153			abc9 = true;
154			flowmap = false;
155			device_opt = "hx";
156			no_rw_check = false;
157			latches = "error";
158		}
159	
160		void execute(std::vector<std::string> args, RTLIL::Design *design) override
161		{
162			string run_from, run_to;
163			clear_flags();
164	
165			size_t argidx;
166			for (argidx = 1; argidx < args.size(); argidx++)
167			{
168				if (args[argidx] == "-top" && argidx+1 < args.size()) {
169					top_opt = "-top " + args[++argidx];
170					continue;
171				}
172				if (args[argidx] == "-blif" && argidx+1 < args.size()) {
173					blif_file = args[++argidx];
174					continue;
175				}
176				if (args[argidx] == "-edif" && argidx+1 < args.size()) {
177					edif_file = args[++argidx];
178					continue;
179				}
180				if (args[argidx] == "-json" && argidx+1 < args.size()) {
181					json_file = args[++argidx];
182					continue;
183				}
184				if (args[argidx] == "-run" && argidx+1 < args.size()) {
185					size_t pos = args[argidx+1].find(':');
186					if (pos == std::string::npos)
187						break;
188					run_from = args[++argidx].substr(0, pos);
189					run_to = args[argidx].substr(pos+1);
190					continue;
191				}
192				if (args[argidx] == "-flatten") {
193					flatten = true;
194					continue;
195				}
196				if (args[argidx] == "-noflatten") {
197					flatten = false;
198					continue;
199				}
200				if (args[argidx] == "-retime") {
201					retime = true;
202					continue;
203				}
204				if (args[argidx] == "-relut") {
205					// removed, opt_lut is always run
206					continue;
207				}
208				if (args[argidx] == "-nocarry") {
209					nocarry = true;
210					continue;
211				}
212				if (args[argidx] == "-nodffe") {
213					nodffe = true;
214					continue;
215				}
216				if (args[argidx] == "-dffe_min_ce_use" && argidx+1 < args.size()) {
217					min_ce_use = atoi(args[++argidx].c_str());
218					continue;
219				}
220				if (args[argidx] == "-nobram") {
221					nobram = true;
222					continue;
223				}
224				if (args[argidx] == "-spram") {
225					spram = true;
226					continue;
227				}
228				if (args[argidx] == "-dsp") {
229					dsp = true;
230					continue;
231				}
232				if (args[argidx] == "-noabc") {
233					noabc = true;
234					continue;
235				}
236				if (args[argidx] == "-abc2") {
237					abc2 = true;
238					continue;
239				}
240				if (args[argidx] == "-vpr") {
241					vpr = true;
242					continue;
243				}
244				if (args[argidx] == "-abc9") {
245					// removed, ABC9 is on by default.
246					continue;
247				}
248				if (args[argidx] == "-noabc9") {
249					abc9 = false;
250					continue;
251				}
252				if (args[argidx] == "-dff") {
253					dff = true;
254					continue;
255				}
256				if (args[argidx] == "-device" && argidx+1 < args.size()) {
257					device_opt = args[++argidx];
258					continue;
259				}
260				if (args[argidx] == "-flowmap") {
261					flowmap = true;
262					continue;
263				}
264				if (args[argidx] == "-no-rw-check") {
265					no_rw_check = true;
266					continue;
267				}
268				if (args[argidx] == "-latches" && argidx+1 < args.size()) {
269					latches = args[++argidx];
270					continue;
271				}
272				break;
273			}
274			extra_args(args, argidx, design);
275	
276			if (!design->full_selection())
277				log_cmd_error("This command only operates on fully selected designs!\n");
278			if (device_opt != "hx" && device_opt != "lp" && device_opt !="u")
279				log_cmd_error("Invalid or no device specified: '%s'\n", device_opt);
280			if (latches != "info" && latches != "warn" && latches != "error")
281				log_cmd_error("Invalid value '%s' for -latches (expected info, warn or error)\n", latches.c_str());
282	
283			if (abc9 && retime)
284				log_cmd_error("-retime option not currently compatible with -abc9!\n");
285			if (abc9 && noabc)
286				log_cmd_error("-abc9 is incompatible with -noabc!\n");
287			if (abc9 && flowmap)
288				log_cmd_error("-abc9 is incompatible with -flowmap!\n");
289			if (flowmap && noabc)
290				log_cmd_error("-flowmap is incompatible with -noabc!\n");
291	
292			log_header(design, "Executing SYNTH_ICE40 pass.\n");
293			log_push();
294	
295			run_script(design, run_from, run_to);
296	
297			log_pop();
298		}
299	
300		void script() override
301		{
302			std::string define;
303			if (device_opt == "lp")
304				define = "-D ICE40_LP";
305			else if (device_opt == "u")
306				define = "-D ICE40_U";
307			else
308				define = "-D ICE40_HX";
309			std::string no_rw_check_opt = "";
310			if (no_rw_check)
311				no_rw_check_opt = " -no-rw-check";
312			if (help_mode)
313				no_rw_check_opt = " [-no-rw-check]";
314	
315			if (check_label("begin"))
316			{
317				run("read_verilog " + define + " -lib -specify +/ice40/cells_sim.v");
318				run(stringf("hierarchy -check %s", help_mode ? "-top <top>" : top_opt));
319				run("proc -latches " + (latches == "info" ? std::string("info") : std::string("warn")));
320			}
321	
322			if (check_label("flatten", "(unless -noflatten)"))
323			{
324				if (flatten) {
325					run("check");
326					run("flatten");
327					run("tribuf -logic");
328					run("deminout");
329				}
330			}
331	
332			if (check_label("coarse"))
333			{
334				run("opt_expr");
335				run("opt_clean");
336				run("check");
337				run("opt -nodffe -nosdff");
338				run("fsm");
339				run("opt");
340				run("wreduce");
341				run("peepopt");
342				run("opt_clean");
343				run("share");
344				run("techmap -map +/cmp2lut.v -D LUT_WIDTH=4");
345				run("opt_expr");
346				run("opt_clean");
347				if (help_mode || dsp) {
348					run("memory_dff" + no_rw_check_opt); // ice40_dsp will merge registers, reserve memory port registers first
349					run("wreduce t:$mul");
350					run("techmap -map +/mul2dsp.v -map +/ice40/dsp_map.v -D DSP_A_MAXWIDTH=16 -D DSP_B_MAXWIDTH=16 "
351							"-D DSP_A_MINWIDTH=2 -D DSP_B_MINWIDTH=2 -D DSP_Y_MINWIDTH=11 "
352							"-D DSP_NAME=$__MUL16X16", "(if -dsp)");
353					run("select a:mul2dsp", "              (if -dsp)");
354					run("setattr -unset mul2dsp", "        (if -dsp)");
355					run("opt_expr -fine", "                (if -dsp)");
356					run("wreduce", "                       (if -dsp)");
357					run("select -clear", "                 (if -dsp)");
358					run("ice40_dsp", "                     (if -dsp)");
359					run("chtype -set $mul t:$__soft_mul", "(if -dsp)");
360				}
361				run("alumacc");
362				run("opt");
363				run("memory -nomap" + no_rw_check_opt);
364				run("opt_clean");
365			}
366	
367			if (check_label("map_ram"))
368			{
369				std::string args = "";
370				if (help_mode)
371					args += " [-no-auto-huge] [-no-auto-block]";
372				else {
373					if (!spram)
374						args += " -no-auto-huge";
375					if (nobram)
376						args += " -no-auto-block";
377				}
378				run("memory_libmap -lib +/ice40/brams.txt -lib +/ice40/spram.txt" + args, "(-no-auto-huge unless -spram, -no-auto-block if -nobram)");
379				run("techmap -map +/ice40/brams_map.v -map +/ice40/spram_map.v");
380				run("ice40_braminit");
381			}
382	
383			if (check_label("map_ffram"))
384			{
385				run("opt -fast -mux_undef -undriven -fine");
386				run("memory_map");
387				run("opt -undriven -fine");
388			}
389	
390			if (check_label("map_gates"))
391			{
392				if (nocarry)
393					run("techmap");
394				else {
395					run("ice40_wrapcarry");
396					run("techmap -map +/techmap.v -map +/ice40/arith_map.v");
397				}
398				run("opt -fast");
399				if (retime || help_mode)
400					run("abc -dff -D 1", "(only if -retime)");
401				run("ice40_opt");
402			}
403	
404			if (check_label("map_ffs"))
405			{
406				if (nodffe)
407					run(stringf("dfflegalize -cell $_DFF_?_ 0 -cell $_DFF_?P?_ 0 -cell $_SDFF_?P?_ 0 -cell $_DLATCH_?_ x"));
408				else
409					run(stringf("dfflegalize -cell $_DFF_?_ 0 -cell $_DFFE_?P_ 0 -cell $_DFF_?P?_ 0 -cell $_DFFE_?P?P_ 0 -cell $_SDFF_?P?_ 0 -cell $_SDFFCE_?P?P_ 0 -cell $_DLATCH_?_ x -mince %d", min_ce_use));
410				run("techmap -map +/ice40/ff_map.v");
411				run("opt_expr -mux_undef");
412				run("simplemap");
413				run("ice40_opt -full");
414			}
415	
416			if (check_label("map_luts"))
417			{
418				if (abc2 || help_mode) {
419					run("abc", "      (only if -abc2)");
420					run("ice40_opt", "(only if -abc2)");
421				}
422				if (latches == "error" || help_mode)
423					run("check -latchonly -assert", "(only if -latches error, the default)");
424				run("techmap -map +/ice40/latches_map.v");
425				if (noabc || flowmap || help_mode) {
426					run("simplemap", "                               (if -noabc or -flowmap)");
427					if (noabc || help_mode)
428						run("techmap -map +/gate2lut.v -D LUT_WIDTH=4", "(only if -noabc)");
429					if (flowmap || help_mode)
430						run("flowmap -maxlut 4", "(only if -flowmap)");
431				}
432				if (!noabc) {
433					if (abc9) {
434						run("read_verilog " + define + " -icells -lib -specify +/ice40/abc9_model.v");
435						std::string abc9_opts;
436						std::string k = "synth_ice40.abc9.W";
437						if (active_design && active_design->scratchpad.count(k))
438							abc9_opts += stringf(" -W %s", active_design->scratchpad_get_string(k));
439						else {
440							k = stringf("synth_ice40.abc9.%s.W", device_opt);
441							abc9_opts += stringf(" -W %s", RTLIL::constpad.at(k));
442						}
443						if (dff)
444							abc9_opts += " -dff";
445						run("abc9 " + abc9_opts);
446					}
447					else
448						run(stringf("abc -dress -lut 4 %s", dff ? "-dff" : ""), "(skip if -noabc)");
449				}
450				run("ice40_wrapcarry -unwrap");
451				run("techmap -map +/ice40/ff_map.v");
452				run("clean");
453				run("opt_lut -tech ice40");
454			}
455	
456			if (check_label("map_cells"))
457			{
458				if (help_mode)
459					run("techmap -map +/ice40/cells_map.v", "(skip if -vpr)");
460				else if (!vpr)
461					run("techmap -map +/ice40/cells_map.v");
462				run("clean");
463			}
464	
465			if (check_label("check"))
466			{
467				run("autoname");
468				run("hierarchy -check");
469				run("stat");
470				run("check -noinit");
471				run("blackbox =A:whitebox");
472			}
473	
474			if (check_label("blif"))
475			{
476				if (!blif_file.empty() || help_mode) {
477					if (vpr || help_mode) {
478						run(stringf("opt_clean -purge"),
479								"                                 (vpr mode)");
480						run(stringf("write_blif -attr -cname -conn -param %s",
481								help_mode ? "<file-name>" : blif_file.c_str()),
482								" (vpr mode)");
483					}
484					if (!vpr)
485						run(stringf("write_blif -gates -attr -param %s",
486								help_mode ? "<file-name>" : blif_file.c_str()),
487								"       (non-vpr mode)");
488				}
489			}
490	
491			if (check_label("edif"))
492			{
493				if (!edif_file.empty() || help_mode)
494					run(stringf("write_edif %s", help_mode ? "<file-name>" : edif_file));
495			}
496	
497			if (check_label("json"))
498			{
499				if (!json_file.empty() || help_mode)
500					run(stringf("write_json %s", help_mode ? "<file-name>" : json_file));
501			}
502		}
503	} SynthIce40Pass;
504	
505	PRIVATE_NAMESPACE_END
506

