162			noiopad = false;
163			noclkbuf = false;
164			nocarry = false;
165			nobram = false;
166			nolutram = false;
167			nosrl = false;
168			nocarry = false;
169			nowidelut = false;
170			nodsp = false;
171			uram = false;
172			abc9 = false;
173			dff = false;
174			flatten_before_abc = false;
175			widemux = 0;
176			lut_size = 6;
177		}
