179		void execute(std::vector<std::string> args, RTLIL::Design *design) override
180		{
181			std::string run_from, run_to;
182			clear_flags();
183	
184			size_t argidx;
185			for (argidx = 1; argidx < args.size(); argidx++)
186			{
187				if (args[argidx] == "-top" && argidx+1 < args.size()) {
188					top_opt = "-top " + args[++argidx];
189					continue;
190				}
191				if ((args[argidx] == "-family" || args[argidx] == "-arch") && argidx+1 < args.size()) {
192					family = args[++argidx];
193					continue;
194				}
195				if (args[argidx] == "-edif" && argidx+1 < args.size()) {
196					edif_file = args[++argidx];
197					continue;
198				}
199				if (args[argidx] == "-blif" && argidx+1 < args.size()) {
200					blif_file = args[++argidx];
201					continue;
202				}
203				if (args[argidx] == "-run" && argidx+1 < args.size()) {
204					size_t pos = args[argidx+1].find(':');
205					if (pos == std::string::npos)
206						break;
207					run_from = args[++argidx].substr(0, pos);
208					run_to = args[argidx].substr(pos+1);
209					continue;
210				}
211				if (args[argidx] == "-flatten") {
212					flatten = true;
213					continue;
214				}
215				if (args[argidx] == "-flatten_before_abc") {
216					flatten_before_abc = true;
217					continue;
218				}
219				if (args[argidx] == "-retime") {
220					dff = true;
221					retime = true;
222					continue;
223				}
224				if (args[argidx] == "-nocarry") {
225					nocarry = true;
226					continue;
227				}
228				if (args[argidx] == "-nowidelut") {
229					nowidelut = true;
230					continue;
231				}
232				if (args[argidx] == "-ise") {
233					ise = true;
234					continue;
235				}
236				if (args[argidx] == "-iopad") {
237					continue;
238				}
239				if (args[argidx] == "-noiopad") {
240					noiopad = true;
241					continue;
242				}
243				if (args[argidx] == "-noclkbuf") {
244					noclkbuf = true;
245					continue;
246				}
247				if (args[argidx] == "-nocarry") {
248					nocarry = true;
249					continue;
250				}
251				if (args[argidx] == "-nobram") {
252					nobram = true;
253					continue;
254				}
255				if (args[argidx] == "-nolutram" || /*deprecated alias*/ args[argidx] == "-nodram") {
256					nolutram = true;
257					continue;
258				}
259				if (args[argidx] == "-nosrl") {
260					nosrl = true;
261					continue;
262				}
263				if (args[argidx] == "-widemux" && argidx+1 < args.size()) {
264					widemux = atoi(args[++argidx].c_str());
265					continue;
266				}
267				if (args[argidx] == "-abc9") {
268					abc9 = true;
269					continue;
270				}
271				if (args[argidx] == "-nodsp") {
272					nodsp = true;
273					continue;
274				}
275				if (args[argidx] == "-uram") {
276					uram = true;
277					continue;
278				}
279				if (args[argidx] == "-dff") {
280					dff = true;
281					continue;
282				}
283				if (args[argidx] == "-json" && argidx+1 < args.size()) {
284					json_file = args[++argidx];
285					continue;
286				}
287				break;
288			}
289			extra_args(args, argidx, design);
290	
291			if (family == "xcup" || family == "xcu") {
292				lut_size = 6;
293				widelut_size = 9;
294			} else if (family == "xc7" ||
295					family == "xc6v" ||
296					family == "xc5v" ||
297					family == "xc6s") {
298				lut_size = 6;
299				widelut_size = 8;
300			} else if (family == "xc4v" ||
301					family == "xc3sda" ||
302					family == "xc3sa" ||
303					family == "xc3se" ||
304					family == "xc3s" ||
305					family == "xc2vp" ||
306					family == "xc2v") {
307				lut_size = 4;
308				widelut_size = 8;
309			} else if (family == "xcve" || family == "xcv") {
310				lut_size = 4;
311				widelut_size = 6;
312			} else
313				log_cmd_error("Invalid Xilinx -family setting: '%s'.\n", family);
314	
315			if (widemux != 0 && lut_size != 6)
316				log_cmd_error("-widemux is not currently supported for LUT4-based architectures.\n");
317	
318			if (lut_size != 6) {
319				log_warning("Shift register inference not yet supported for family %s.\n", family);
320				nosrl = true;
321			}
322	
323			if (widemux != 0 && widemux < 2)
324				log_cmd_error("-widemux value must be 0 or >= 2.\n");
325	
326			if (!design->full_selection())
327				log_cmd_error("This command only operates on fully selected designs!\n");
328	
329			if (abc9 && retime)
330				log_cmd_error("-retime option not currently compatible with -abc9!\n");
331	
332			log_header(design, "Executing SYNTH_XILINX pass.\n");
333			log_push();
334	
335			run_script(design, run_from, run_to);
336	
337			log_pop();
338		}
