340		void script() override
341		{
342			std::string lut_size_s = std::to_string(lut_size);
343			if (help_mode)
344				lut_size_s = "[46]";
345	
346			if (check_label("begin")) {
347				std::string read_args;
348				read_args += " -lib -specify +/xilinx/cells_sim.v";
349				run("read_verilog" + read_args);
350	
351				run("read_verilog -lib +/xilinx/cells_xtra.v");
352	
353				run(stringf("hierarchy -check %s", top_opt));
354			}
355	
356			if (check_label("prepare")) {
357				run("proc");
358				if (flatten || help_mode) {
359					run("check");
360					run("flatten", "(with '-flatten')");
361				}
362				if (active_design)
363					active_design->scratchpad_unset("tribuf.added_something");
364				run("tribuf -logic");
365				if (noiopad && active_design && active_design->scratchpad_get_bool("tribuf.added_something"))
366					log_error("Tristate buffers are unsupported without the '-iopad' option.\n");
367				run("deminout");
368				run("opt_expr");
369				run("opt_clean");
370				run("check");
371				run("opt -nodffe -nosdff");
372				run("fsm");
373				run("opt");
374				if (help_mode)
375					run("wreduce [-keepdc]", "(option for '-widemux')");
376				else
377					run("wreduce" + std::string(widemux > 0 ? " -keepdc" : ""));
378				run("peepopt");
379				run("opt_clean");
380	
381				if (widemux > 0 || help_mode)
382					run("muxpack", "    ('-widemux' only)");
383	
384				// xilinx_srl looks for $shiftx cells for identifying variable-length
385				//   shift registers, so attempt to convert $pmux-es to this
386				// Also: wide multiplexer inference benefits from this too
387				if (!(nosrl && widemux == 0) || help_mode) {
388					run("pmux2shiftx", "(skip if '-nosrl' and '-widemux=0')");
389					run("clean", "      (skip if '-nosrl' and '-widemux=0')");
390				}
391	
392				run("sort");
393			}
394	
395			if (check_label("map_dsp", "(skip if '-nodsp')")) {
396				if (!nodsp || help_mode) {
397					run("memory_dff"); // xilinx_dsp will merge registers, reserve memory port registers first
