628					run("dfflegalize -cell $_DFFE_?P?P_ r -cell $_SDFFE_?P?P_ r -cell $_DLATCH_?P?_ r", "(for xc6s)");
629				else if (family == "xc6v" || family == "xc7" || family == "xcu" || family == "xcup")
630					run("dfflegalize -cell $_DFFE_?P?P_ 01 -cell $_SDFFE_?P?P_ 01 -cell $_DLATCH_?P?_ 01", "(for xc6v, xc7, xcu, xcup)");
631				else
632					run("dfflegalize -cell $_DFFE_?P?P_ 01 -cell $_DFFSRE_?PPP_ 01 -cell $_SDFFE_?P?P_ 01 -cell $_DLATCH_?P?_ 01 -cell $_DLATCHSR_?PP_ 01", "(for xc5v and older)");
633				if (abc9 || help_mode) {
634					if (dff || help_mode)
635						run("zinit -all w:* t:$_SDFFE_*", "('-dff' only)");
636					run("techmap -map +/xilinx/ff_map.v", "('-abc9' only)");
637				}
638			}
639	
640			if (check_label("map_luts")) {
641				run("opt_expr -mux_undef -noclkinv");
642				if (flatten_before_abc) {
643					run("check");
644					run("flatten");
645				}
646				if (help_mode)
647					run("abc -luts 2:2,3,6:5[,10,20] [-dff] [-D 1]", "(option for '-nowidelut', '-dff', '-retime')");
648				else if (abc9) {
649					if (lut_size != 6)
650						log_error("'synth_xilinx -abc9' not currently supported for LUT4-based devices.\n");
651					if (family != "xc7")
652						log_warning("'synth_xilinx -abc9' not currently supported for the '%s' family, "
653								"will use timing for 'xc7' instead.\n", family.c_str());
654					run("read_verilog -icells -lib -specify +/xilinx/abc9_model.v");
655					std::string abc9_opts;
656					std::string k = "synth_xilinx.abc9.W";
657					if (active_design && active_design->scratchpad.count(k))
658						abc9_opts += stringf(" -W %s", active_design->scratchpad_get_string(k));
659					else {
660						k = stringf("synth_xilinx.abc9.%s.W", family);
661						abc9_opts += stringf(" -W %s", RTLIL::constpad.at(k, RTLIL::constpad.at("synth_xilinx.abc9.xc7.W")));
662					}
663					if (nowidelut)
664						abc9_opts += stringf(" -maxlut %d", lut_size);
665					if (dff)
666						abc9_opts += " -dff";
667					run("abc9" + abc9_opts);
668				}
669				else {
670					std::string abc_opts;
671					if (lut_size != 6) {
672						if (nowidelut)
673							abc_opts += " -lut " + lut_size_s;
674						else
675							abc_opts += " -lut " + lut_size_s + ":" + std::to_string(widelut_size);
676					} else {
677						if (nowidelut)
678							abc_opts += " -luts 2:2,3,6:5";
679						else if (widelut_size == 8)
680							abc_opts += " -luts 2:2,3,6:5,10,20";
681						else
682							abc_opts += " -luts 2:2,3,6:5,10,20,40";
683					}
684					if (dff)
685						abc_opts += " -dff";
686					if (retime)
687						abc_opts += " -D 1";
688					run("abc" + abc_opts);
689				}
690				run("clean");
691	
692				if (help_mode || !abc9)
693					run("techmap -map +/xilinx/ff_map.v", "(only if not '-abc9')");
694				// This shregmap call infers fixed length shift registers after abc
695				//   has performed any necessary retiming
696				if (!nosrl || help_mode)
697					run("xilinx_srl -fixed -minlen 3", "(skip if '-nosrl')");
698				std::string techmap_args = "-map +/xilinx/lut_map.v -map +/xilinx/cells_map.v";
699				techmap_args += " -D LUT_WIDTH=" + lut_size_s;
700				run("techmap " + techmap_args);
701				if (help_mode)
702					run("xilinx_dffopt [-lut4]");
703				else if (lut_size == 4)
704					run("xilinx_dffopt -lut4");
705				else
706					run("xilinx_dffopt");
707				run("opt_lut_ins -tech xilinx");
708			}
709	
710			if (check_label("finalize")) {
711				if (help_mode || !noclkbuf)
712					run("clkbufmap -buf BUFG O:I", "(skip if '-noclkbuf')");
713				if (help_mode || ise)
714					run("extractinv -inv INV O:I", "(only if '-ise')");
715				run("clean");
716			}
717	
718			if (check_label("check")) {
719				run("hierarchy -check");
720				run("stat -tech xilinx");
721				run("check -noinit");
722				run("blackbox =A:whitebox");
723			}
724	
725			if (check_label("edif")) {
726				if (!edif_file.empty() || help_mode)
727					run(stringf("write_edif -pvector bra %s", edif_file));
728			}
729	
730			if (check_label("blif")) {
731				if (!blif_file.empty() || help_mode)
732					run(stringf("write_blif %s", blif_file));
733			}
734	
735			if (check_label("json"))
736			{
737				if (!json_file.empty() || help_mode)
738					run(stringf("write_json %s", help_mode ? "<file-name>" : json_file));
739			}
740		}
741	} SynthXilinxPass;
742	
743	PRIVATE_NAMESPACE_END
744

