21	module \$__SHREG_ (input C, input D, input E, output Q);
22	  parameter DEPTH = 0;
23	  parameter [DEPTH-1:0] INIT = 0;
24	  parameter CLKPOL = 1;
25	  parameter ENPOL = 2;
26	
27	  \$__XILINX_SHREG_ #(.DEPTH(DEPTH), .INIT(INIT), .CLKPOL(CLKPOL), .ENPOL(ENPOL)) _TECHMAP_REPLACE_ (.C(C), .D(D), .L(DEPTH-1), .E(E), .Q(Q));
28	endmodule
29	
30	module \$__XILINX_SHREG_ (input C, input D, input [31:0] L, input E, output Q, output SO);
31	  parameter DEPTH = 0;
32	  parameter [DEPTH-1:0] INIT = 0;
33	  parameter CLKPOL = 1;
34	  parameter ENPOL = 2;
35	
36	  // shregmap's INIT parameter shifts out LSB first;
37	  // however Xilinx expects MSB first
38	  function [DEPTH-1:0] brev;
39	    input [DEPTH-1:0] din;
40	    integer i;
41	    begin
42	      for (i = 0; i < DEPTH; i=i+1)
43	        brev[i] = din[DEPTH-1-i];
44	    end
45	  endfunction
46	  localparam [DEPTH-1:0] INIT_R = brev(INIT);
47	
48	  parameter _TECHMAP_CONSTMSK_L_ = 0;
49	
50	  wire CE;
51	  generate
52	    if (ENPOL == 0)
53	      assign CE = ~E;
54	    else if (ENPOL == 1)
55	      assign CE = E;
56	    else
57	      assign CE = 1'b1;
58	    if (DEPTH == 1) begin
59	      if (CLKPOL)
60	          FDRE #(.INIT(INIT_R)) _TECHMAP_REPLACE_ (.D(D), .Q(Q), .C(C), .CE(CE), .R(1'b0));
61	      else
62	          FDRE_1 #(.INIT(INIT_R)) _TECHMAP_REPLACE_ (.D(D), .Q(Q), .C(C), .CE(CE), .R(1'b0));
63	    end else
64	    if (DEPTH <= 16) begin
65	      SRL16E #(.INIT(INIT_R), .IS_CLK_INVERTED(~CLKPOL[0])) _TECHMAP_REPLACE_ (.A0(L[0]), .A1(L[1]), .A2(L[2]), .A3(L[3]), .CE(CE), .CLK(C), .D(D), .Q(Q));
66	    end else
67	    if (DEPTH > 17 && DEPTH <= 32) begin
68	      SRLC32E #(.INIT(INIT_R), .IS_CLK_INVERTED(~CLKPOL[0])) _TECHMAP_REPLACE_ (.A(L[4:0]), .CE(CE), .CLK(C), .D(D), .Q(Q));
69	    end else
70	    if (DEPTH > 33 && DEPTH <= 64) begin
71	      wire T0, T1, T2;
72	      SRLC32E #(.INIT(INIT_R[32-1:0]), .IS_CLK_INVERTED(~CLKPOL[0])) fpga_srl_0 (.A(L[4:0]), .CE(CE), .CLK(C), .D(D), .Q(T0), .Q31(T1));
73	      \$__XILINX_SHREG_ #(.DEPTH(DEPTH-32), .INIT(INIT[DEPTH-32-1:0]), .CLKPOL(CLKPOL), .ENPOL(ENPOL)) fpga_srl_1 (.C(C), .D(T1), .L(L), .E(E), .Q(T2));
74	      if (&_TECHMAP_CONSTMSK_L_)
75	        assign Q = T2;
76	      else
77	        MUXF7 fpga_mux_0 (.O(Q), .I0(T0), .I1(T2), .S(L[5]));
78	    end else
79	    if (DEPTH > 65 && DEPTH <= 96) begin
80	      wire T0, T1, T2, T3, T4, T5, T6;
81	      SRLC32E #(.INIT(INIT_R[32-1: 0]), .IS_CLK_INVERTED(~CLKPOL[0])) fpga_srl_0 (.A(L[4:0]), .CE(CE), .CLK(C), .D( D), .Q(T0), .Q31(T1));
82	      SRLC32E #(.INIT(INIT_R[64-1:32]), .IS_CLK_INVERTED(~CLKPOL[0])) fpga_srl_1 (.A(L[4:0]), .CE(CE), .CLK(C), .D(T1), .Q(T2), .Q31(T3));
83	      \$__XILINX_SHREG_ #(.DEPTH(DEPTH-64), .INIT(INIT[DEPTH-64-1:0]), .CLKPOL(CLKPOL), .ENPOL(ENPOL)) fpga_srl_2 (.C(C), .D(T3), .L(L[4:0]), .E(E), .Q(T4));
84	      if (&_TECHMAP_CONSTMSK_L_)
85	        assign Q = T4;
86	      else
87	        \$__XILINX_MUXF78 fpga_hard_mux (.I0(T0), .I1(T2), .I2(T4), .I3(1'bx), .S0(L[5]), .S1(L[6]), .O(Q));
88	    end else
89	    if (DEPTH > 97 && DEPTH < 128) begin
90	      wire T0, T1, T2, T3, T4, T5, T6, T7, T8;
91	      SRLC32E #(.INIT(INIT_R[32-1: 0]), .IS_CLK_INVERTED(~CLKPOL[0])) fpga_srl_0 (.A(L[4:0]), .CE(CE), .CLK(C), .D( D), .Q(T0), .Q31(T1));
92	      SRLC32E #(.INIT(INIT_R[64-1:32]), .IS_CLK_INVERTED(~CLKPOL[0])) fpga_srl_1 (.A(L[4:0]), .CE(CE), .CLK(C), .D(T1), .Q(T2), .Q31(T3));
93	      SRLC32E #(.INIT(INIT_R[96-1:64]), .IS_CLK_INVERTED(~CLKPOL[0])) fpga_srl_2 (.A(L[4:0]), .CE(CE), .CLK(C), .D(T3), .Q(T4), .Q31(T5));
94	      \$__XILINX_SHREG_ #(.DEPTH(DEPTH-96), .INIT(INIT[DEPTH-96-1:0]), .CLKPOL(CLKPOL), .ENPOL(ENPOL)) fpga_srl_3 (.C(C), .D(T5), .L(L[4:0]), .E(E), .Q(T6));
95	      if (&_TECHMAP_CONSTMSK_L_)
96	        assign Q = T6;
97	      else
98	        \$__XILINX_MUXF78 fpga_hard_mux (.I0(T0), .I1(T2), .I2(T4), .I3(T6), .S0(L[5]), .S1(L[6]), .O(Q));
99	    end
100	    else if (DEPTH == 128) begin
101	      wire T0, T1, T2, T3, T4, T5, T6;
102	      SRLC32E #(.INIT(INIT_R[ 32-1: 0]), .IS_CLK_INVERTED(~CLKPOL[0])) fpga_srl_0 (.A(L[4:0]), .CE(CE), .CLK(C), .D( D), .Q(T0), .Q31(T1));
103	      SRLC32E #(.INIT(INIT_R[ 64-1:32]), .IS_CLK_INVERTED(~CLKPOL[0])) fpga_srl_1 (.A(L[4:0]), .CE(CE), .CLK(C), .D(T1), .Q(T2), .Q31(T3));
104	      SRLC32E #(.INIT(INIT_R[ 96-1:64]), .IS_CLK_INVERTED(~CLKPOL[0])) fpga_srl_2 (.A(L[4:0]), .CE(CE), .CLK(C), .D(T3), .Q(T4), .Q31(T5));
105	      SRLC32E #(.INIT(INIT_R[128-1:96]), .IS_CLK_INVERTED(~CLKPOL[0])) fpga_srl_3 (.A(L[4:0]), .CE(CE), .CLK(C), .D(T5), .Q(T6), .Q31(SO));
106	      if (&_TECHMAP_CONSTMSK_L_)
107	        assign Q = T6;
108	      else
109	        \$__XILINX_MUXF78 fpga_hard_mux (.I0(T0), .I1(T2), .I2(T4), .I3(T6), .S0(L[5]), .S1(L[6]), .O(Q));
110	    end
111	    // For fixed length, if just 1 over a convenient value, decompose
112	    else if (DEPTH <= 129 && &_TECHMAP_CONSTMSK_L_) begin
113	      wire T;
114	      \$__XILINX_SHREG_ #(.DEPTH(DEPTH-1), .INIT(INIT[DEPTH-1:1]), .CLKPOL(CLKPOL), .ENPOL(ENPOL)) fpga_srl      (.C(C), .D(D), .L({32{1'b1}}), .E(E), .Q(T));
115	      \$__XILINX_SHREG_ #(.DEPTH(1),       .INIT(INIT[0]),         .CLKPOL(CLKPOL), .ENPOL(ENPOL)) fpga_srl_last (.C(C), .D(T), .L(L), .E(E), .Q(Q));
116	    end
117	    // For variable length, if just 1 over a convenient value, then bump up one more
118	    else if (DEPTH < 129 && ~&_TECHMAP_CONSTMSK_L_)
119	      \$__XILINX_SHREG_ #(.DEPTH(DEPTH+1), .INIT({INIT,1'b0}), .CLKPOL(CLKPOL), .ENPOL(ENPOL)) _TECHMAP_REPLACE_ (.C(C), .D(D), .L(L), .E(E), .Q(Q));
120	    else begin
121	      localparam depth0 = 128;
122	      localparam num_srl128 = DEPTH / depth0;
123	      localparam depthN = DEPTH % depth0;
124	      wire [num_srl128 + (depthN > 0 ? 1 : 0) - 1:0] T;
125	      wire [num_srl128 + (depthN > 0 ? 1 : 0) :0] S;
126	      assign S[0] = D;
127	      genvar i;
128	      for (i = 0; i < num_srl128; i++)
129	        \$__XILINX_SHREG_ #(.DEPTH(depth0), .INIT(INIT[DEPTH-1-i*depth0-:depth0]), .CLKPOL(CLKPOL), .ENPOL(ENPOL)) fpga_srl      (.C(C), .D(S[i]),          .L(L[$clog2(depth0)-1:0]), .E(E), .Q(T[i]), .SO(S[i+1]));
130	
131	      if (depthN > 0)
132	        \$__XILINX_SHREG_ #(.DEPTH(depthN), .INIT(INIT[depthN-1:0]),               .CLKPOL(CLKPOL), .ENPOL(ENPOL)) fpga_srl_last (.C(C), .D(S[num_srl128]), .L(L[$clog2(depth0)-1:0]), .E(E), .Q(T[num_srl128]));
133	
134	      if (&_TECHMAP_CONSTMSK_L_)
135	        assign Q = T[num_srl128 + (depthN > 0 ? 1 : 0) - 1];
136	      else
137	        assign Q = T[L[DEPTH-1:$clog2(depth0)]];
138	    end
139	  endgenerate
140	endmodule
141	
142	`ifdef MIN_MUX_INPUTS
143	module \$__XILINX_SHIFTX (A, B, Y);
144	  parameter A_SIGNED = 0;
145	  parameter B_SIGNED = 0;
146	  parameter A_WIDTH = 1;
147	  parameter B_WIDTH = 1;
148	  parameter Y_WIDTH = 1;
149	
150	  (* force_downto *)
151	  input [A_WIDTH-1:0] A;
152	  (* force_downto *)
153	  input [B_WIDTH-1:0] B;
154	  (* force_downto *)
155	  output [Y_WIDTH-1:0] Y;
156	
157	  parameter [A_WIDTH-1:0] _TECHMAP_CONSTMSK_A_ = 0;
158	  parameter [A_WIDTH-1:0] _TECHMAP_CONSTVAL_A_ = 0;
159	  parameter [B_WIDTH-1:0] _TECHMAP_CONSTMSK_B_ = 0;
160	  parameter [B_WIDTH-1:0] _TECHMAP_CONSTVAL_B_ = 0;
161	
162	  function integer A_WIDTH_trimmed;
163	    input integer start;
164	  begin
165	    A_WIDTH_trimmed = start;
166	    while (A_WIDTH_trimmed > 0 && _TECHMAP_CONSTMSK_A_[A_WIDTH_trimmed-1] && _TECHMAP_CONSTVAL_A_[A_WIDTH_trimmed-1] === 1'bx)
167	      A_WIDTH_trimmed = A_WIDTH_trimmed - 1;
168	  end
169	  endfunction
170	
171	  generate
172	    genvar i, j;
173	    // Bit-blast
174	    if (Y_WIDTH > 1) begin
175	      for (i = 0; i < Y_WIDTH; i++)
176	        \$__XILINX_SHIFTX  #(.A_SIGNED(A_SIGNED), .B_SIGNED(B_SIGNED), .A_WIDTH(A_WIDTH-Y_WIDTH+1), .B_WIDTH(B_WIDTH), .Y_WIDTH(1'd1)) bitblast (.A(A[A_WIDTH-Y_WIDTH+i:i]), .B(B), .Y(Y[i]));
177	    end
178	    // If the LSB of B is constant zero (and Y_WIDTH is 1) then
179	    //   we can optimise by removing every other entry from A
180	    //   and popping the constant zero from B
181	    else if (_TECHMAP_CONSTMSK_B_[0] && !_TECHMAP_CONSTVAL_B_[0]) begin
182	      wire [(A_WIDTH+1)/2-1:0] A_i;
183	      for (i = 0; i < (A_WIDTH+1)/2; i++)
184	        assign A_i[i] = A[i*2];
185	      \$__XILINX_SHIFTX  #(.A_SIGNED(A_SIGNED), .B_SIGNED(B_SIGNED), .A_WIDTH((A_WIDTH+1'd1)/2'd2), .B_WIDTH(B_WIDTH-1'd1), .Y_WIDTH(Y_WIDTH)) _TECHMAP_REPLACE_ (.A(A_i), .B(B[B_WIDTH-1:1]), .Y(Y));
186	    end
187	    // Trim off any leading 1'bx -es in A
188	    else if (_TECHMAP_CONSTMSK_A_[A_WIDTH-1] && _TECHMAP_CONSTVAL_A_[A_WIDTH-1] === 1'bx) begin
189	      localparam A_WIDTH_new = A_WIDTH_trimmed(A_WIDTH-1);
190	      if (A_WIDTH_new == 0)
191	        assign Y = 1'bx;
192	      else
193	        \$__XILINX_SHIFTX  #(.A_SIGNED(A_SIGNED), .B_SIGNED(B_SIGNED), .A_WIDTH(A_WIDTH_new), .B_WIDTH(B_WIDTH), .Y_WIDTH(Y_WIDTH)) _TECHMAP_REPLACE_ (.A(A[A_WIDTH_new-1:0]), .B(B), .Y(Y));
194	    end
195	    else if (A_WIDTH < `MIN_MUX_INPUTS) begin
196	      wire _TECHMAP_FAIL_ = 1;
197	    end
198	    else if (A_WIDTH == 2) begin
199	      MUXF7 fpga_hard_mux (.I0(A[0]), .I1(A[1]), .S(B[0]), .O(Y));
200	    end
201	    else if (A_WIDTH <= 4) begin
202	      wire [4-1:0] Ax;
203	      if (A_WIDTH == 4)
204	        assign Ax = A;
205	      else
206	        // Rather than extend with 1'bx which gets flattened to 1'b0
207	        // causing the "don't care" status to get lost, extend with
208	        // the same driver of F7B.I0 so that we can optimise F7B away
209	        // later
210	        assign Ax = {A[1], A};
211	      \$__XILINX_MUXF78 fpga_hard_mux (.I0(Ax[0]), .I1(Ax[2]), .I2(Ax[1]), .I3(Ax[3]), .S0(B[1]), .S1(B[0]), .O(Y));
212	    end
213	    // Note that the following decompositions are 'backwards' in that
214	    // the LSBs are placed on the hard resources, and the soft resources
215	    // are used for MSBs.
216	    // This has the effect of more effectively utilising the hard mux;
217	    // take for example a 5:1 multiplexer, currently this would map as:
218	    //
219	    //     A[0] \___  __                             A[0] \__  __
220	    //     A[4] /   \|  \       whereas the more     A[1] /  \|  \
221	    //     A[1] _____|   |      obvious mapping      A[2] \___|   |
222	    //     A[2] _____|   |--    of MSBs to hard      A[3] /   |   |__
223	    //     A[3]______|   |      resources would      A[4] ____|   |
224	    //               |__/       lead to:             1'bx ____|   |
225	    //                ||                                      |__/
226	    //                ||                                       ||
227	    //              B[1:0]                                   B[1:2]
228	    //
229	    // Expectation would be that the 'forward' mapping (right) is more
230	    // area efficient (consider a 9:1 multiplexer using 2x4:1 multiplexers
231	    // on its I0 and I1 inputs, and A[8] and 1'bx on its I2 and I3 inputs)
232	    // but that the 'backwards' mapping (left) is more delay efficient
233	    // since smaller LUTs are faster than wider ones.
234	    else if (A_WIDTH <= 8) begin
235	      wire [8-1:0] Ax = {{{8-A_WIDTH}{1'bx}}, A};
236	      wire T0 = B[2] ? Ax[4] : Ax[0];
237	      wire T1 = B[2] ? Ax[5] : Ax[1];
238	      wire T2 = B[2] ? Ax[6] : Ax[2];
239	      wire T3 = B[2] ? Ax[7] : Ax[3];
240	      \$__XILINX_MUXF78 fpga_hard_mux (.I0(T0), .I1(T2), .I2(T1), .I3(T3), .S0(B[1]), .S1(B[0]), .O(Y));
241	    end
242	    else if (A_WIDTH <= 16) begin
243	      wire [16-1:0] Ax = {{{16-A_WIDTH}{1'bx}}, A};
244	      wire T0 = B[2] ? B[3] ? Ax[12] : Ax[4]
245	                     : B[3] ? Ax[ 8] : Ax[0];
246	      wire T1 = B[2] ? B[3] ? Ax[13] : Ax[5]
247	                     : B[3] ? Ax[ 9] : Ax[1];
248	      wire T2 = B[2] ? B[3] ? Ax[14] : Ax[6]
249	                     : B[3] ? Ax[10] : Ax[2];
250	      wire T3 = B[2] ? B[3] ? Ax[15] : Ax[7]
251	                     : B[3] ? Ax[11] : Ax[3];
252	      \$__XILINX_MUXF78 fpga_hard_mux (.I0(T0), .I1(T2), .I2(T1), .I3(T3), .S0(B[1]), .S1(B[0]), .O(Y));
253	    end
254	    else begin
255	      localparam num_mux16 = (A_WIDTH+15) / 16;
256	      localparam clog2_num_mux16 = $clog2(num_mux16);
257	      wire [num_mux16-1:0] T;
258	      wire [num_mux16*16-1:0] Ax = {{(num_mux16*16-A_WIDTH){1'bx}}, A};
259	      for (i = 0; i < num_mux16; i++)
260	        \$__XILINX_SHIFTX  #(
261	          .A_SIGNED(A_SIGNED),
262	          .B_SIGNED(B_SIGNED),
263	          .A_WIDTH(16),
264	          .B_WIDTH(4),
265	          .Y_WIDTH(Y_WIDTH)
266	        ) fpga_mux (
267	          .A(Ax[i*16+:16]),
268	          .B(B[3:0]),
269	          .Y(T[i])
270	        );
271	      \$__XILINX_SHIFTX  #(
272	          .A_SIGNED(A_SIGNED),
273	          .B_SIGNED(B_SIGNED),
274	          .A_WIDTH(num_mux16),
275	          .B_WIDTH(clog2_num_mux16),
276	          .Y_WIDTH(Y_WIDTH)
277	      ) _TECHMAP_REPLACE_ (
278	          .A(T),
279	          .B(B[B_WIDTH-1-:clog2_num_mux16]),
280	          .Y(Y));
281	    end
282	  endgenerate
283	endmodule
284	
285	(* techmap_celltype = "$__XILINX_SHIFTX" *)
286	module _90__XILINX_SHIFTX (A, B, Y);
287	  parameter A_SIGNED = 0;
288	  parameter B_SIGNED = 0;
289	  parameter A_WIDTH = 1;
290	  parameter B_WIDTH = 1;
291	  parameter Y_WIDTH = 1;
292	
293	  (* force_downto *)
294	  input [A_WIDTH-1:0] A;
295	  (* force_downto *)
296	  input [B_WIDTH-1:0] B;
297	  (* force_downto *)
298	  output [Y_WIDTH-1:0] Y;
299	
300	  \$shiftx  #(.A_SIGNED(A_SIGNED), .B_SIGNED(B_SIGNED), .A_WIDTH(A_WIDTH), .B_WIDTH(B_WIDTH), .Y_WIDTH(Y_WIDTH)) _TECHMAP_REPLACE_ (.A(A), .B(B), .Y(Y));
301	endmodule
302	
303	module \$_MUX_ (A, B, S, Y);
304	  input A, B, S;
305	  output Y;
306	  generate
307	    if (`MIN_MUX_INPUTS == 2)
308	      \$__XILINX_SHIFTX  #(.A_SIGNED(0), .B_SIGNED(0), .A_WIDTH(2), .B_WIDTH(1), .Y_WIDTH(1)) _TECHMAP_REPLACE_ (.A({B,A}), .B(S), .Y(Y));
309	    else
310	      wire _TECHMAP_FAIL_ = 1;
311	  endgenerate
312	endmodule
313	
314	module \$_MUX4_ (A, B, C, D, S, T, Y);
315	  input A, B, C, D, S, T;
316	  output Y;
317	  \$__XILINX_SHIFTX  #(.A_SIGNED(0), .B_SIGNED(0), .A_WIDTH(4), .B_WIDTH(2), .Y_WIDTH(1)) _TECHMAP_REPLACE_ (.A({D,C,B,A}), .B({T,S}), .Y(Y));
318	endmodule
319	
320	module \$_MUX8_ (A, B, C, D, E, F, G, H, S, T, U, Y);
321	  input A, B, C, D, E, F, G, H, S, T, U;
322	  output Y;
323	  \$__XILINX_SHIFTX  #(.A_SIGNED(0), .B_SIGNED(0), .A_WIDTH(8), .B_WIDTH(3), .Y_WIDTH(1)) _TECHMAP_REPLACE_ (.A({H,G,F,E,D,C,B,A}), .B({U,T,S}), .Y(Y));
324	endmodule
325	
326	module \$_MUX16_ (A, B, C, D, E, F, G, H, I, J, K, L, M, N, O, P, S, T, U, V, Y);
327	  input A, B, C, D, E, F, G, H, I, J, K, L, M, N, O, P, S, T, U, V;
328	  output Y;
329	  \$__XILINX_SHIFTX  #(.A_SIGNED(0), .B_SIGNED(0), .A_WIDTH(16), .B_WIDTH(4), .Y_WIDTH(1)) _TECHMAP_REPLACE_ (.A({P,O,N,M,L,K,J,I,H,G,F,E,D,C,B,A}), .B({V,U,T,S}), .Y(Y));
330	endmodule
331	`endif
332	
333	module \$__XILINX_MUXF78 (O, I0, I1, I2, I3, S0, S1);
334	  output O;
335	  input I0, I1, I2, I3, S0, S1;
336	  wire T0, T1;
337	  parameter _TECHMAP_BITS_CONNMAP_ = 0;
338	  parameter [_TECHMAP_BITS_CONNMAP_-1:0] _TECHMAP_CONNMAP_I0_ = 0;
339	  parameter [_TECHMAP_BITS_CONNMAP_-1:0] _TECHMAP_CONNMAP_I1_ = 0;
340	  parameter [_TECHMAP_BITS_CONNMAP_-1:0] _TECHMAP_CONNMAP_I2_ = 0;
341	  parameter [_TECHMAP_BITS_CONNMAP_-1:0] _TECHMAP_CONNMAP_I3_ = 0;
342	  parameter _TECHMAP_CONSTMSK_S0_ = 0;
343	  parameter _TECHMAP_CONSTVAL_S0_ = 0;
344	  parameter _TECHMAP_CONSTMSK_S1_ = 0;
345	  parameter _TECHMAP_CONSTVAL_S1_ = 0;
346	  if (_TECHMAP_CONSTMSK_S0_ && _TECHMAP_CONSTVAL_S0_ === 1'b1)
347	    assign T0 = I1;
348	  else if (_TECHMAP_CONSTMSK_S0_ || _TECHMAP_CONNMAP_I0_ === _TECHMAP_CONNMAP_I1_)
349	    assign T0 = I0;
350	  else
351	    MUXF7 mux7a (.I0(I0), .I1(I1), .S(S0), .O(T0));
352	  if (_TECHMAP_CONSTMSK_S0_ && _TECHMAP_CONSTVAL_S0_ === 1'b1)
353	    assign T1 = I3;
354	  else if (_TECHMAP_CONSTMSK_S0_ || _TECHMAP_CONNMAP_I2_ === _TECHMAP_CONNMAP_I3_)
355	    assign T1 = I2;
356	  else
357	    MUXF7 mux7b (.I0(I2), .I1(I3), .S(S0), .O(T1));
358	  if (_TECHMAP_CONSTMSK_S1_ && _TECHMAP_CONSTVAL_S1_ === 1'b1)
359	    assign O = T1;
360	  else if (_TECHMAP_CONSTMSK_S1_ || (_TECHMAP_CONNMAP_I0_ === _TECHMAP_CONNMAP_I1_ && _TECHMAP_CONNMAP_I1_ === _TECHMAP_CONNMAP_I2_ && _TECHMAP_CONNMAP_I2_ === _TECHMAP_CONNMAP_I3_))
361	    assign O = T0;
362	  else
363	    MUXF8 mux8 (.I0(T0), .I1(T1), .S(S1), .O(O));
364	endmodule
